#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; bool ispossible(string s, string x){    if (s.size()>x.size()) return false;    for (int i=0;i<x.size()-s.size()+1;i++){        if (x.substr(i,s.size())==s) return true;    }    return false;}   // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        long long n,m;        cin>>n>>m;        string x;        cin>>x;        string s;        cin>>s;                 string x0=x;        string x1=x0 + x0;        string x2=x1 + x1;        string x3=x2 + x2;        string x4=x3 + x3;        string x5=x4 + x4;        long long ans=-1;        if (ispossible(s,x0)) ans=0;        else if (ispossible(s,x1)) ans=1;        else if (ispossible(s,x2)) ans=2;        else if (ispossible(s,x3)) ans=3;        else if (ispossible(s,x4)) ans=4;        else if (ispossible(s,x5)) ans=5;        cout<<ans<<"\n";     }    return 0;}